25	// testRunFunc is the signature for running project tests.
26	// Returns (output, success).
27	type testRunFunc func(projectRoot string) (string, bool)
28	
29	var qualityGateVerbose bool
30	
31	// maxFixTasksPerStep caps the number of active fix-tasks per quality-gate step.
32	// When this limit is reached, no new fix-tasks are created for that step.
33	const maxFixTasksPerStep = 3
34	
35	// ErrMaxFixTasks is returned when the maximum number of active fix-tasks for a
36	// quality-gate step has been reached.
37	var ErrMaxFixTasks = errors.New("max fix-tasks reached")
38	
39	var qualityGateCmd = &cobra.Command{
40		Use:   "quality-gate",
41		Short: "Check if all tasks are done, then run tests",
42		Long: `Checks if every task in the current feature is completed or skipped.
43	Exits 0 silently if any task is still pending, in_progress, or blocked (no-op).
44	If all done: runs project-wide unit tests, then test regression.
45	
46	Feature test scripts are run by T-test-run (run-test task), not this hook.
47	This hook is the project health gate: unit tests + regression suite.
48	
49	Use -v to see why the command exits early (useful for debugging).`,
50		Args: cobra.NoArgs,
51		RunE: runQualityGate,
52	}
53	
54	func init() {
55		qualityGateCmd.Flags().BoolVarP(&qualityGateVerbose, "verbose", "v", false, "print debug info when exiting early")
56	}
57	
58	// AllCompletedResult holds context for running tests after all tasks complete.
59	type AllCompletedResult struct {
60		FeatureSlug string
61		ProjectRoot string
62		DocsOnly    bool // true if no implementation or fix tasks exist
63	}
64	
65	// checkAllCompleted verifies all tasks are done and returns test context.
66	// Returns (nil, nil) when tasks are not all done — caller should exit silently.
67	// Returns (nil, error) for infrastructure failures (no project, no feature).
68	func checkAllCompleted(verbose bool) (*AllCompletedResult, error) {
69		projectRoot, err := project.FindProjectRoot()
70		if err != nil {
71			Debugf(verbose, "project root not found: %v", err)
72			return nil, base.ErrProjectNotFound()
73		}
74		Debugf(verbose, "project root: %s", projectRoot)
75	
76		featureSlug, err := feature.GetCurrentFeature(projectRoot)
77		if err != nil {
78			Debugf(verbose, "feature not found: %v", err)
79			return nil, base.ErrFeatureNotSet()
80		}
81		Debugf(verbose, "feature: %s", featureSlug)
82	
83		// Guard: only proceed if .forge/state.json signals allCompleted.
84		forgeState := feature.ReadForgeState(projectRoot)
85		if forgeState == nil || !forgeState.AllCompleted {
86			Debugf(verbose, "no forge state with allCompleted — skipping")
87			return nil, nil
88		}
89		Debugf(verbose, "forge state: feature=%s allCompleted=true", forgeState.Feature)
90	
91		// Consume the state — clear it before proceeding
92		_ = feature.ClearForgeState(projectRoot)
93	
94		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
95		index, err := task.LoadIndex(indexPath)
96		if err != nil {
97			Debugf(verbose, "index.json not found: %s (%v)", indexPath, err)
98			return nil, nil
99		}
100		Debugf(verbose, "loaded index: %d tasks", index.TaskCount())
101	
102		// All tasks must be completed or skipped (rejected does not count as done)
103		for _, t := range index.TasksMap() {
104			if t.Status != feature.StatusCompleted && t.Status != feature.StatusSkipped {
105				Debugf(verbose, "task %s is %s — not all done", t.ID, t.Status)
106				return nil, nil
107			}
108		}
109	
110		return &AllCompletedResult{
111			FeatureSlug: featureSlug,
112			ProjectRoot: projectRoot,
113			DocsOnly:    isDocsOnly(index),
114		}, nil
115	}
116	
117	// isDocsOnly returns true if no task has a testable runtime behavior type.
118	// Docs-only features change only markdown files — no compile/test needed.
119	// Unlike needsTestPipeline in pkg/task, this checks ALL tasks including auto-generated ones.
120	func isDocsOnly(index *task.TaskIndex) bool {
121		for _, t := range index.TasksMap() {
122			if task.IsTestableType(t.Type) {
123				return false
124			}
125		}
126		return true
127	}
128	
129	func runQualityGate(_ *cobra.Command, _ []string) error {
130		result, err := checkAllCompleted(qualityGateVerbose)
131		if err != nil {
132			base.Exit(err)
133		}
134		if result == nil {
135			return nil // not all done is normal, exit silently
136		}
137	
138		fmt.Fprintf(os.Stderr, "=== All tasks completed for feature: %s ===\n", result.FeatureSlug)
139	
140		// Docs-only features have no code changes — skip compile/test gates.
141		if result.DocsOnly {
142			fmt.Fprintln(os.Stderr, "Feature is docs-only — skipping quality gate (no implementation or fix tasks)")
143			os.Exit(0)
144		}
145	
146		// Warn if feature test scripts exist but haven't been promoted.
147		// NOTE: staging/graduation directories removed in v3.0.0 — this check
148		// is retained as a no-op placeholder for future test-run validation.
149		_ = result.ProjectRoot
150		_ = result.FeatureSlug
151	
152		// Step 1: Quality gate (compile -> fmt -> lint)
153		// Stops at first blocking failure.
154		gateSteps := just.NonBreakingGateSequence()
155		var gateBlockErr error
156		just.RunGate(result.ProjectRoot, "", gateSteps, func(step, output string) {
157			fmt.Fprintf(os.Stderr, "ERROR: %s check failed\n", step)
158			errorDocPath := "tests/results/unit-raw-output.txt"
159			if output != "" {
160				if err := testrunner.WriteUnitTestRawOutput(result.ProjectRoot, "=== "+step+" failure ===\n"+output); err != nil {
161					fmt.Fprintf(os.Stderr, "WARNING: failed to write %s output: %v\n", step, err)
162				}
163			}
164			fixID, fixErr := addFixTask(result.ProjectRoot, result.FeatureSlug, step, output, errorDocPath)
165			if fixErr != nil {
166				fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
167			}
168			gateBlockErr = handleGateFailure(step, errorDocPath, fixID, just.ExtractConciseError(output, 5), fixTypeFromStep(step) == task.TypeCodingFix)
169		})
170		if gateBlockErr != nil {
171			os.Exit(0)
172		}
173	
174		// Step 2: Project-wide unit tests (with retry-once policy)
175		fmt.Fprintln(os.Stderr, "--- Running project-wide tests ---")
176		unitPassed, unitFixID, unitErr := runUnitTestStep(
177			result.ProjectRoot, result.FeatureSlug,
178			testrunner.RunProjectTests,
179		)
180		if unitErr != nil {
181			fmt.Fprintf(os.Stderr, "WARNING: %v\n", unitErr)
182		}
183		if !unitPassed {
184			unitOutput := "" // output already written by runUnitTestStep
185			errorDocPath := "tests/results/unit-raw-output.txt"
186			if err := handleGateFailure("unit-test", errorDocPath, unitFixID, just.ExtractConciseError(unitOutput, 5), true); err != nil {
187				os.Exit(0)
188			}
189		}
190	
191		// Step 3: Full test regression (promoted scripts in tests/)
192		if err := runTestRegression(result.ProjectRoot, result.FeatureSlug); err != nil {
193			os.Exit(0)
194		}
195		return nil
196	}
197	
198	// runTestRegression runs the full test regression suite when a justfile with
199	// a test recipe is present. When surfaces are configured in .forge/config.yaml,
200	// it orchestrates per-surface lifecycle (dev→probe→test→teardown for web/api/mobile;
201	// test→teardown for cli/tui). Falls back to legacy behavior when no surfaces configured.
202	// Returns an error when a gate failure is detected, nil otherwise.
203	func runTestRegression(projectRoot, featureSlug string) error {
204		if !just.HasJustfile(projectRoot) || !just.HasRecipe(projectRoot, "test") {
205			return nil
206		}
207	
208		// Detect surface types from config.
209		surfaces, _ := forgeconfig.ReadSurfaces(projectRoot)
210		surfaceTypes := forgeconfig.SurfaceTypes(surfaces)
211	
212		if len(surfaceTypes) == 0 {
213			// No surfaces configured — fall back to legacy behavior.
214			return runTestRegressionLegacy(projectRoot, featureSlug)
215		}
216	
217		// Surface-aware orchestration: run lifecycle per surface type.
218		return runTestRegressionSurface(projectRoot, featureSlug, surfaceTypes)
219	}
220	
221	// runTestRegressionLegacy is the pre-surface-aware test regression logic.
222	// Runs test-setup (optional), serverprobe health check, then just test.
223	func runTestRegressionLegacy(projectRoot, featureSlug string) error {
224		// Optional setup step — skip regression on failure.
225		if just.HasRecipe(projectRoot, "test-setup") {
226			fmt.Fprintln(os.Stderr, "--- Ensuring test dependencies (just test-setup) ---")
227			setupOutput, setupSuccess := just.RunCapture(projectRoot, "just", "test-setup")
228			if !setupSuccess {
229				fmt.Fprintln(os.Stderr, "WARNING: test-setup failed; skipping test regression")
230				fmt.Fprintln(os.Stderr, "  To retry manually: just test-setup && just test")
231				if setupOutput != "" {
232					if err := testrunner.WriteRegressionRawOutput(projectRoot, "=== test-setup failure ===\n"+setupOutput); err != nil {
233						fmt.Fprintf(os.Stderr, "WARNING: failed to write setup output: %v\n", err)
234					} else {
235						fmt.Fprintln(os.Stderr, "  Setup output saved to tests/results/raw-output.txt")
236					}
237				}
238				return nil
239			}
240		}
241	
242		// Health check — skip regression if servers aren't ready.
243		if !serverprobe.ProbeServers(projectRoot, "") {
244			fmt.Fprintln(os.Stderr, "WARNING: server health check failed; skipping test regression")
245			fmt.Fprintln(os.Stderr, "  Start dev server and retry: just dev && just test")
246			return nil
247		}
248	
249		// Run the regression suite.
250		fmt.Fprintln(os.Stderr, "--- Running full test regression (just test) ---")
251		regressionOutput, regSuccess := just.RunCapture(projectRoot, "just", "test")
252		if !regSuccess {
253			fmt.Fprintln(os.Stderr, "ERROR: test regression failed")
254			errorDocPath := "tests/results/raw-output.txt"
255			if regressionOutput != "" {
256				if err := testrunner.WriteRegressionRawOutput(projectRoot, regressionOutput); err != nil {
257					fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
258				}
259			}
260			fixID, fixErr := addFixTask(projectRoot, featureSlug, "test", regressionOutput, errorDocPath)
261			if fixErr != nil {
262				fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
263			}
264			return handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(regressionOutput, 5), true)
265		}
266		return nil
267	}
268	
269	// runTestRegressionSurface orchestrates per-surface-type lifecycle sequences.
270	// For each unique surface type, runs the appropriate sequence:
271	//   - web/api/mobile: dev → probe → test → teardown (full lifecycle)
272	//   - cli/tui: test → teardown (simplified)
273	//
274	// Surfaces of the same type share a single lifecycle (dev/probe run once per type).
275	// Teardown is mandatory regardless of prior step success/failure.
276	func runTestRegressionSurface(projectRoot, featureSlug string, surfaceTypes []string) error {
277		var lastErr error
278		for _, surfaceType := range surfaceTypes {
279			fmt.Fprintf(os.Stderr, "--- Running surface orchestration for %s ---\n", surfaceType)
280			result := runSurfaceLifecycle(projectRoot, surfaceType)
281			if !result.success {
282				errorDocPath := "tests/results/raw-output.txt"
283				if result.output != "" {
284					if err := testrunner.WriteRegressionRawOutput(projectRoot, result.output); err != nil {
285						fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
286					}
287				}
288				fixID, fixErr := addFixTask(projectRoot, featureSlug, "test", result.output, errorDocPath)
289				if fixErr != nil {
290					fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
291				}
292				lastErr = handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(result.output, 5), true)
293			}
294		}
295		return lastErr
296	}
297	
298	// lifecycleResult holds the result of a surface lifecycle execution.
299	type lifecycleResult struct {
300		success bool
301		output  string
302	}
303	
304	// needsFullLifecycle returns true for surface types that require dev→probe→test→teardown.
305	// cli and tui surfaces use the simplified test→teardown sequence.
306	func needsFullLifecycle(surfaceType string) bool {
307		return surfaceType == "web" || surfaceType == "api" || surfaceType == "mobile"
308	}
309	
310	// resolveRecipe attempts to find a surface-specific recipe (e.g., "web-dev"),
311	// falling back to the generic recipe (e.g., "dev") if not found.
312	// Returns the recipe name to use, or empty string if neither exists.
313	func resolveRecipe(projectRoot, surfaceType, genericRecipe string) string {
314		specificRecipe := surfaceType + "-" + genericRecipe
315		if just.HasRecipe(projectRoot, specificRecipe) {
316			return specificRecipe
317		}
318		if just.HasRecipe(projectRoot, genericRecipe) {
319			return genericRecipe
320		}
321		return ""
322	}
323	
324	// runSurfaceLifecycle executes the per-surface lifecycle sequence.
325	// For web/api/mobile: dev → probe → test → teardown
326	// For cli/tui: test → teardown
327	// Teardown always executes (via defer-like pattern).
328	func runSurfaceLifecycle(projectRoot, surfaceType string) lifecycleResult {
329		full := needsFullLifecycle(surfaceType)
330	
331		// Phase 1: Dev (full lifecycle only)
332		if full {
333			recipe := resolveRecipe(projectRoot, surfaceType, "dev")
334			if recipe != "" {
335				fmt.Fprintf(os.Stderr, "  Starting dev server (just %s)...\n", recipe)
336				output, success := just.RunCapture(projectRoot, "just", recipe)
337				if !success {
338					fmt.Fprintf(os.Stderr, "  ERROR: dev failed (just %s)\n", recipe)
339					runTeardown(projectRoot, surfaceType)
340					return lifecycleResult{success: false, output: output}
341				}
342			}
343		}
344	
345		// Phase 2: Probe (full lifecycle only)
346		if full {
347			probeRecipe := resolveRecipe(projectRoot, surfaceType, "probe")
348			if !probeWithRetry(projectRoot, probeRecipe, 3, 5*time.Second) {
349				fmt.Fprintln(os.Stderr, "  ERROR: probe failed after retries")
350				runTeardown(projectRoot, surfaceType)
351				return lifecycleResult{success: false, output: "probe failed: server not responding after 3 retries"}
352			}
353		}
354	
355		// Phase 3: Test
356		var result lifecycleResult
357		testRecipe := resolveRecipe(projectRoot, surfaceType, "test")
358		if testRecipe != "" {
359			fmt.Fprintf(os.Stderr, "  Running tests (just %s)...\n", testRecipe)
360			output, success := just.RunCapture(projectRoot, "just", testRecipe)
361			result = lifecycleResult{success: success, output: output}
362			if !success {
363				fmt.Fprintln(os.Stderr, "  ERROR: test failed")
364			}
365		} else {
366			result = lifecycleResult{success: true}
367		}
368	
369		// Phase 4: Teardown (always)
370		runTeardown(projectRoot, surfaceType)
371	
372		return result
373	}
374	
375	// runTeardown executes the teardown recipe for a surface type.
376	// Errors are logged but never fail the lifecycle — teardown is best-effort cleanup.
377	func runTeardown(projectRoot, surfaceType string) {
378		recipe := resolveRecipe(projectRoot, surfaceType, "teardown")
379		if recipe != "" {
380			fmt.Fprintf(os.Stderr, "  Running teardown (just %s)...\n", recipe)
381			output, success := just.RunCapture(projectRoot, "just", recipe)
382			if !success {
383				fmt.Fprintf(os.Stderr, "  WARNING: teardown failed (just %s)\n", recipe)
384				if output != "" {
385					fmt.Fprintf(os.Stderr, "  %s\n", just.ExtractConciseError(output, 3))
386				}
387			}
388		}
389	}
390	
391	// probeWithRetry runs the probe recipe with the specified number of retries.
392	// Returns true if the probe succeeds within the retry count.
393	// Returns true (skip) if the probe recipe doesn't exist.
394	// interval is the delay between retries (0 for no delay, useful in tests).
395	func probeWithRetry(projectRoot, probeRecipe string, maxRetries int, interval time.Duration) bool {
396		if probeRecipe == "" {
397			return true // no probe recipe — skip
398		}
399	
400		// Verify the recipe actually exists before retrying.
401		if !just.HasRecipe(projectRoot, probeRecipe) {
402			return true // recipe not found — skip
403		}
404	
405		for attempt := range maxRetries {
406			if attempt > 0 && interval > 0 {
407				fmt.Fprintf(os.Stderr, "  Probe retry %d/%d (waiting %v)...\n", attempt+1, maxRetries, interval)
408				time.Sleep(interval)
409			}
410			fmt.Fprintf(os.Stderr, "  Probing (just %s) attempt %d/%d...\n", probeRecipe, attempt+1, maxRetries)
411			_, success := just.RunCapture(projectRoot, "just", probeRecipe)
412			if success {
413				fmt.Fprintln(os.Stderr, "  Probe succeeded")
414				return true
415			}
416		}
417		return false
418	}
419	
420	// handleGateFailure prints the hook JSON block reason and returns an error
421	// signalling that the gate blocked. The caller (RunE handler) decides exit behavior.
422	// fixID is the ID returned by addFixTask; empty means task creation failed.
423	// breaking indicates whether the fix task blocks downstream tasks.
424	func handleGateFailure(step, errorDocPath, fixID, concise string, breaking bool) error {
425		action := "run `forge task add --type coding.fix` to create one manually, then `forge task claim`"
426		if fixID != "" {
427			action = "run `forge task claim` to pick it up"
428		}
429	
430		guide := map[string]string{
431			"compile":   "fix compilation errors",
432			"lint":      "fix lint errors",
433			"unit-test": "fix failing unit tests",
434			"test":      "fix failing tests",
435		}
436		label := map[string]string{
437			"compile":   "Project compilation",
438			"lint":      "Lint check",
439			"unit-test": "Unit tests",
440			"test":      "Advanced tests",
441		}
442	
443		g := guide[step]
444		if g == "" {
445			g = "fix the issue"
446		}
447		l := label[step]
448		if l == "" {
449			l = testrunner.Capitalize(step) + " check"
450		}
451	
452		var fixMsg string
453		if fixID != "" {
454			fixMsg = fmt.Sprintf("Fix task %s added (P0, breaking=%v)", fixID, breaking)
455		} else {
456			fixMsg = "Failed to add fix task automatically"
457		}
458	
459		reason := fmt.Sprintf(
460			"%s failed in quality-gate hook. %s — %s and %s.\nError output: %s\n%s",
461			l, fixMsg, action, g, errorDocPath, concise)
462	
463		testrunner.PrintHookJSON(map[string]any{
464			"decision": "block",
465			"reason":   reason,
466		})
467		return fmt.Errorf("quality gate blocked: %s", step)
468	}
469	
470	// runUnitTestStep runs unit tests with a retry-once policy for transient failures.
471	// On first failure, tests are re-run once. If retry passes, a warning is logged and
472	// no fix task is created. If retry also fails, a fix task is created with both outputs.
473	// Returns (passed, fixTaskID, error).
474	func runUnitTestStep(projectRoot, featureSlug string, runTest testRunFunc) (bool, string, error) {
475		unitOutput, unitSuccess := runTest(projectRoot)
476		if unitSuccess {
477			return true, "", nil
478		}
479	
480		// First attempt failed — retry once.
481		fmt.Fprintln(os.Stderr, "WARNING: unit tests failed on first attempt, retrying once...")
482		retryOutput, retrySuccess := runTest(projectRoot)
483		if retrySuccess {
484			fmt.Fprintln(os.Stderr, "WARNING: unit tests passed on retry (transient failure)")
485			return true, "", nil
486		}
487	
488		// Both attempts failed — write combined output and create fix task.
489		fmt.Fprintln(os.Stderr, "ERROR: unit tests failed (retried once, both attempts failed)")
490		errorDocPath := "tests/results/unit-raw-output.txt"
491		combinedOutput := fmt.Sprintf(
492			"retried once, both attempts failed\n\n=== First attempt ===\n%s\n\n=== Retry attempt ===\n%s",
493			unitOutput, retryOutput,
494		)
495		if combinedOutput != "" {
496			if err := testrunner.WriteUnitTestRawOutput(projectRoot, combinedOutput); err != nil {
497				fmt.Fprintf(os.Stderr, "WARNING: failed to write unit test output: %v\n", err)
498			}
499		}
500	
501		fixID, fixErr := addFixTask(projectRoot, featureSlug, "unit-test", combinedOutput, errorDocPath)
502		return false, fixID, fixErr
503	}
504	
505	// inferSurface attempts to determine the surface-key and surface-type for a
506	// fix-task by querying forge surfaces with all extracted source file paths.
507	// Returns ("", "") on any failure (no surfaces configured, no match, parse error)
508	// — the caller falls back to empty values and fix-task creation proceeds unblocked.
509	// Uses all source files (not just the first) to correctly handle multi-surface projects
510	// where different files may belong to different surfaces.
511	func inferSurface(projectRoot, sourceFiles string) (surfaceKey, surfaceType string) {
512		surfaces, err := forgeconfig.ReadSurfaces(projectRoot)
513		if err != nil || len(surfaces) == 0 {
514			return "", ""
515		}
516	
517		// Parse all source file paths from the comma-separated list.
518		// sourceFiles may be "See error output for affected files" when no files found.
519		if sourceFiles == "" || strings.HasPrefix(sourceFiles, "See error") {
520			return "", ""
521		}
522	
523		var files []string
524		for _, part := range strings.Split(sourceFiles, ",") {
525			f := strings.TrimSpace(part)
526			if f != "" {
527				files = append(files, f)
528			}
529		}
530		if len(files) == 0 {
531			return "", ""
532		}
533	
534		// Try each file until one matches a configured surface.
535		for _, file := range files {
536			match, err := forgeconfig.MatchSurface(surfaces, file)
537			if err == nil {
538				return match.Key, match.Type
539			}
540		}
541		return "", ""
542	}
543	
544	// sourceFileRe matches source file paths followed by :line or :line:col patterns.
545	var sourceFileRe = regexp.MustCompile(`([\w][\w./-]*\.\w{1,10})(?::\d+){1,2}`)
546	
547	// sourceExts is a whitelist of source code extensions for file extraction.
548	var sourceExts = map[string]bool{
549		".go": true, ".ts": true, ".js": true, ".tsx": true, ".jsx": true,
550		".py": true, ".rs": true, ".java": true, ".rb": true,
551		".c": true, ".cpp": true, ".h": true, ".hpp": true,
552		".css": true, ".scss": true, ".html": true, ".sql": true,
553		".vue": true, ".svelte": true,
554	}
555	
556	// extractSourceFiles parses error output and returns comma-separated file paths.
557	func extractSourceFiles(output string) string {
558		seen := make(map[string]bool)
559		var files []string
560		for _, match := range sourceFileRe.FindAllStringSubmatch(output, -1) {
561			path := strings.TrimPrefix(match[1], "./")
562			if path == "" || seen[path] {
563				continue
564			}
565			if !sourceExts[filepath.Ext(path)] {
566				continue
567			}
568			seen[path] = true
569			files = append(files, path)
570		}
571	
572		if len(files) > 10 {
573			files = files[:10]
574		}
575		if len(files) == 0 {
576			return "See error output for affected files"
577		}
578		return strings.Join(files, ", ")
579	}
