581	// countFixTasks counts active (non-terminal) fix-tasks for a step.
582	// A fix-task is identified by having a title with the prefix "fix <step>:".
583	// Terminal statuses (completed, rejected, skipped) are excluded from the count.
584	// This ensures the fix-task cap reflects work-in-progress only.
585	func countFixTasks(index *task.TaskIndex, step string) int {
586		count := 0
587		prefix := "fix " + step + ":"
588		for _, t := range index.TasksMap() {
589			if !strings.HasPrefix(t.Title, prefix) {
590				continue
591			}
592			// Exclude terminal statuses
593			if t.Status == "completed" || t.Status == "rejected" || t.Status == "skipped" {
594				continue
595			}
596			count++
597		}
598		return count
599	}
