601	// fixTypeFromStep returns the deterministic task type for a quality gate failure step.
602	// compile/test failures → TypeCodingFix, fmt/lint failures → TypeCodingCleanup.
603	func fixTypeFromStep(step string) string {
604		switch step {
605		case "compile", "unit-test", "test":
606			return task.TypeCodingFix
607		case "fmt", "lint":
608			return task.TypeCodingCleanup
609		default:
610			return task.TypeCodingFix
611		}
612	}
613	
614	// addFixTask creates fix tasks grouped by test suite (directory) using the same
615	// internal API as `forge task add`. Source files are extracted from the output and
616	// grouped by directory. Each directory group becomes a separate fix-task, enabling
617	// parallel execution and bounded scope. Returns the first task ID on success.
618	// Returns ("", error) on failure: template not found, task add failure, markdown creation failure, or cap exceeded.
619	func addFixTask(projectRoot, featureSlug, step, output, errorDocPath string) (string, error) {
620		sourceFiles := extractSourceFiles(output)
621	
622		// Group source files by directory for parallel execution.
623		groups := groupFilesByDir(sourceFiles)
624	
625		// If no meaningful groups (e.g. "See error output" fallback), create a single task.
626		if len(groups) == 0 {
627			return addSingleFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath)
628		}
629	
630		// One task per directory group.
631		var firstID string
632		for _, group := range groups {
633			id, err := addSingleFixTask(projectRoot, featureSlug, step, group, output, errorDocPath)
634			if err != nil {
635				// If a group fails (e.g. cap reached), return the error.
636				// Already-created tasks remain in the index.
637				return firstID, err
638			}
639			if firstID == "" {
640				firstID = id
641			}
642		}
643		return firstID, nil
644	}
645	
646	// groupFilesByDir splits comma-separated source files into groups by directory.
647	// Files in the same directory stay in one group. Returns nil if files is empty
648	// or the fallback message.
649	func groupFilesByDir(files string) []string {
650		if files == "" || strings.HasPrefix(files, "See error") {
651			return nil
652		}
653	
654		dirMap := make(map[string][]string)
655		for _, f := range strings.Split(files, ",") {
656			f = strings.TrimSpace(f)
657			if f == "" {
658				continue
659			}
660			dir := filepath.Dir(f)
661			dirMap[dir] = append(dirMap[dir], f)
662		}
663	
664		if len(dirMap) <= 1 {
665			// All files in one directory (or no files) — single group.
666			return nil
667		}
668	
669		var groups []string
670		for _, dirFiles := range dirMap {
671			groups = append(groups, strings.Join(dirFiles, ", "))
672		}
673		return groups
674	}
675	
676	// addSingleFixTask creates a single fix task using the same internal API as `forge task add`.
677	// Mirrors executeAdd() from add.go: template defaults -> AddTask -> CreateTaskMarkdown -> EnsureForgeState.
678	// Returns (taskID, nil) on success.
679	// Returns ("", error) on failure: template not found, task add failure, markdown creation failure, or cap exceeded.
680	func addSingleFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath string) (string, error) {
681		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
682	
683		// Check cap before creating a new fix-task.
684		index, err := task.LoadIndex(indexPath)
685		if err != nil {
686			fmt.Fprintf(os.Stderr, "WARNING: failed to load index for cap check: %v\n", err)
687			// Proceed without cap check if index can't be loaded.
688		} else {
689			active := countFixTasks(index, step)
690			if active >= maxFixTasksPerStep {
691				fmt.Fprintf(os.Stderr, "max fix-tasks reached for %s, manual intervention required\n", step)
692				return "", ErrMaxFixTasks
693			}
694		}
695	
696		// Infer surface-key/type from the first extracted source file path.
697		// Falls back to empty strings on any failure (no surfaces, no match, etc.)
698		// so fix-task creation is never blocked by surface inference failure.
699		surfaceKey, surfaceType := inferSurface(projectRoot, sourceFiles)
700	
701		testScript := "just " + step
702	
703		title := fmt.Sprintf("fix %s: %s failure in quality gate", step, testScript)
704		description := fmt.Sprintf(
705			"Quality gate step `%s` failed during quality-gate hook.\n\n"+
706				"Error output saved to: `%s`\n\n"+
707				"Concise error:\n```\n%s\n```",
708			testScript, errorDocPath, just.ExtractConciseError(output, 10),
709		)
710	
711		// Build opts — Priority/Breaking/EstimatedTime sourced from template defaults
712		// when available (dual-source truth: opts is authoritative, template provides defaults).
713		// SourceTaskID is deliberately empty (project-wide gate has no source task).
714		// Vars["SOURCE_TASK_ID"] is "N/A (project-wide gate)" for template rendering.
715		taskType := fixTypeFromStep(step)
716	
717		// Derive Breaking and EstimatedTime from template defaults (dual-source truth).
718		// For coding.cleanup (fmt/lint failures): Breaking=false, EstimatedTime="15min".
719		// For coding.fix (compile/test failures): Breaking=true, EstimatedTime="30min".
720		breaking := true
721		estimatedTime := "30min"
722		if defs, err := tmpl.GetDefaults(taskType); err == nil {
723			breaking = defs.Breaking
724			estimatedTime = defs.EstimatedTime
725		}
726	
727		opts := task.AddTaskOpts{
728			Title:         title,
729			Priority:      "P0",
730			EstimatedTime: estimatedTime,
731			Breaking:      breaking,
732			Description:   description,
733			Template:      taskType,
734			Type:          taskType,
735			SurfaceKey:    surfaceKey,
736			SurfaceType:   surfaceType,
737			Vars: map[string]string{
738				"SOURCE_FILES":   sourceFiles,
739				"TEST_SCRIPT":    testScript,
740				"TEST_RESULTS":   errorDocPath,
741				"SOURCE_TASK_ID": "N/A (project-wide gate)",
742			},
743		}
744	
745		tasksDir := filepath.Join(projectRoot, feature.GetFeatureTasksDir(featureSlug))
746	
747		if _, err := tmpl.Get(opts.Template); err != nil {
748			return "", fmt.Errorf("template %q not found: %w", opts.Template, err)
749		}
750		if defs, err := tmpl.GetDefaults(opts.Template); err == nil && defs.IDPrefix != "" {
751			opts.IDPrefix = defs.IDPrefix
752		}
753	
754		id, err := task.AddTask(indexPath, opts)
755		if err != nil {
756			return "", fmt.Errorf("failed to add fix task: %w", err)
757		}
758	
759		opts.ID = id
760	
761		if err := task.CreateTaskMarkdown(tasksDir, id+".md", opts); err != nil {
762			return "", fmt.Errorf("failed to create fix task file %s: %w", id+".md", err)
763		}
764	
765		if err := feature.EnsureForgeState(projectRoot, featureSlug); err != nil {
766			fmt.Fprintf(os.Stderr, "WARNING: failed to update .forge/state.json: %v\n", err)
767		}
768	
769		fmt.Fprintf(os.Stderr, "Fix task %s added (P0, breaking=%v)\n", id, breaking)
770		return id, nil
771	}
