21			forgeState bool
22			wantNil    bool
23		}{
24			{
25				name: "all completed with forge state returns result",
26				tasks: map[string]task.Task{
27					"t1": {ID: "1.1", Status: "completed"},
28					"t2": {ID: "1.2", Status: "completed"},
29				},
30				forgeState: true,
31				wantNil:    false,
32			},
33			{
34				name: "all skipped with forge state returns result",
35				tasks: map[string]task.Task{
36					"t1": {ID: "1.1", Status: "skipped"},
37				},
38				forgeState: true,
39				wantNil:    false,
40			},
41			{
42				name: "mixed completed and skipped with forge state returns result",
43				tasks: map[string]task.Task{
44					"t1": {ID: "1.1", Status: "completed"},
45					"t2": {ID: "1.2", Status: "skipped"},
46				},
47				forgeState: true,
48				wantNil:    false,
49			},
50			{
51				name: "one pending task returns nil even with forge state",
52				tasks: map[string]task.Task{
53					"t1": {ID: "1.1", Status: "completed"},
54					"t2": {ID: "1.2", Status: "pending"},
55				},
56				forgeState: true,
57				wantNil:    true,
58			},
59			{
60				name: "in_progress task returns nil",
61				tasks: map[string]task.Task{
62					"t1": {ID: "1.1", Status: "in_progress"},
63				},
64				wantNil: true,
65			},
66			{
67				name: "blocked task returns nil",
68				tasks: map[string]task.Task{
69					"t1": {ID: "1.1", Status: "blocked"},
70				},
71				wantNil: true,
72			},
73			{
74				name:       "empty task list with forge state returns result",
