107					if err := feature.WriteForgeState(dir, "test"); err != nil {
108						t.Fatal(err)
109					}
110				}
111				result, _ := checkAllCompleted(false)
112	
113				if tc.wantNil {
114					if result != nil {
115						t.Errorf("expected nil result, got %+v", result)
116					}
117					return
118				}
119				if result == nil {
120					t.Fatal("expected non-nil result, got nil")
121				}
122				if result.FeatureSlug != "test" {
123					t.Errorf("FeatureSlug = %q, want %q", result.FeatureSlug, "test")
124				}
125				if result.ProjectRoot == "" {
126					t.Error("ProjectRoot should not be empty")
127				}
128			})
129		}
130	}
