1126	func TestHandleGateFailure_DistinctReasons(t *testing.T) {
1127		tests := []struct {
1128			step          string
1129			fixID         string
1130			breaking      bool
1131			wantContains  string
1132			wantFixAction string
1133			wantClaim     bool   // expect "task claim" in output
1134			wantManual    bool   // expect "task add --type coding.fix" in output
1135			wantFixMsg    string // expect this fix task message
1136		}{
1137			{"compile", "fix-1", true, "Project compilation failed in quality-gate hook", "fix compilation errors", true, false, "Fix task fix-1 added (P0, breaking=true)"},
1138			{"lint", "fix-2", false, "Lint check failed in quality-gate hook", "fix lint errors", true, false, "Fix task fix-2 added (P0, breaking=false)"},
1139			{"unit-test", "fix-3", true, "Unit tests failed in quality-gate hook", "fix failing unit tests", true, false, "Fix task fix-3 added (P0, breaking=true)"},
1140			{"test", "fix-4", true, "Advanced tests failed in quality-gate hook", "fix failing tests", true, false, "Fix task fix-4 added (P0, breaking=true)"},
1141			{"unknown-step", "fix-5", true, "Unknown-step check failed in quality-gate hook", "fix the issue", true, false, "Fix task fix-5 added (P0, breaking=true)"},
1142			{"compile", "", true, "Project compilation failed in quality-gate hook", "fix compilation errors", false, true, "Failed to add fix task automatically"},
1143		}
1144		for _, tc := range tests {
1145			name := tc.step
1146			if tc.fixID == "" {
1147				name = "nofixid-" + tc.step
1148			}
1149			t.Run(name, func(t *testing.T) {
1150				if os.Getenv("TEST_HANDLE_GATE") == "1" {
1151					_ = handleGateFailure(tc.step, "tests/results/fake.txt", tc.fixID, "some error detail", tc.breaking)
1152					return
1153				}
1154				cmd := exec.Command(os.Args[0], "-test.run=TestHandleGateFailure_DistinctReasons/"+name)
1155				cmd.Env = append(os.Environ(), "TEST_HANDLE_GATE=1")
1156				output, _ := cmd.CombinedOutput()
1157	
1158				got := string(output)
1159				if !strings.Contains(got, tc.wantContains) {
1160					t.Errorf("reason for step %q should contain %q, got:\n%s", tc.step, tc.wantContains, got)
1161				}
1162				if !strings.Contains(got, tc.wantFixAction) {
1163					t.Errorf("reason for step %q should contain fix action %q", tc.step, tc.wantFixAction)
1164				}
1165				if tc.wantClaim && !strings.Contains(got, "task claim") {
1166					t.Errorf("reason for step %q should contain 'task claim'", tc.step)
1167				}
1168				if tc.wantManual && !strings.Contains(got, "task add --type coding.fix") {
1169					t.Errorf("reason for step %q (no fixID) should contain manual add instruction", tc.step)
1170				}
1171				if !strings.Contains(got, tc.wantFixMsg) {
1172					t.Errorf("reason for step %q should contain %q, got:\n%s", tc.step, tc.wantFixMsg, got)
1173				}
1174				if !strings.Contains(got, "tests/results/fake.txt") {
1175					t.Errorf("reason for step %q should reference error doc path", tc.step)
1176				}
1177				if !strings.Contains(got, "some error detail") {
1178					t.Errorf("reason for step %q should include concise error", tc.step)
1179				}
1180			})
1181		}
1182	}
